async function fetchPost() {
  try {
    const response = await fetch('https://jsonplaceholder.typicode.com/posts/1');
    if (!response.ok) {
      throw new Error('Network response was not ok');
    }
    const data = await response.json();
    console.log('Post title:', data.title);
  } catch (error) {
    console.error('Fetch failed:', error.message);
  }
}

fetchPost();

async function fetchMultiplePosts() {
  const urls = [
    'https://jsonplaceholder.typicode.com/posts/1',
    'https://jsonplaceholder.typicode.com/posts/invalid', // invalid URL to test error
    'https://jsonplaceholder.typicode.com/posts/3'
  ];

  try {
    const results = await Promise.all(
      urls.map(async url => {
        const response = await fetch(url);
        if (!response.ok) throw new Error(`Failed to fetch ${url}`);
        return response.json();
      })
    );
    console.log('All posts fetched:', results);
  } catch (error) {
    console.error('One or more fetch requests failed:', error.message);
  }
}

fetchMultiplePosts();

async function fetchAllPostsWithSettled() {
  const urls = [
    'https://jsonplaceholder.typicode.com/posts/1',
    'https://jsonplaceholder.typicode.com/posts/invalid',
    'https://jsonplaceholder.typicode.com/posts/3'
  ];

  const results = await Promise.allSettled(
    urls.map(url => fetch(url).then(async response => {
      if (!response.ok) throw new Error(`Failed: ${url}`);
      return response.json();
    }))
  );

  results.forEach((result, idx) => {
    if (result.status === 'fulfilled') {
      console.log(`Post ${idx + 1} title:`, result.value.title);
    } else {
      console.error(`Post ${idx + 1} error:`, result.reason.message);
    }
  });
}

fetchAllPostsWithSettled();

interface Task {
  id: number;
  title: string;
  completed: boolean;
}

function addTask(title: string): void {
  const newTask: Task = {
    id: tasks.length + 1,
    title,
    completed: false
  };
  tasks.push(newTask);
  console.log(`Added task: \"${title}\"`);
}

function completeTask(id: number): void {
  const task = tasks.find(t => t.id === id);
  if (task) {
    task.completed = true;
    console.log(`Completed task: \"${task.title}\"`);
  } else {
    console.log(`Task with id ${id} not found.`);
  }
}

function showTasks(): void {
  console.log('To-Do List:');
  tasks.forEach(task => {
    const status = task.completed ? '[x]' : '[ ]';
    console.log(`${status} ${task.id}: ${task.title}`);
  });
}

addTask('Learn TypeScript basics');
addTask('Build a to-do list app');
addTask('Test the app');
completeTask(2);
showTasks();

class NetworkError extends Error {
  readonly code: number;

  constructor(message: string, code: number) {
    super(message);
    this.code = code;
    this.name = 'NetworkError';
  }
}

class ValidationError extends Error {
  readonly field: string;

  constructor(message: string, field: string) {
    super(message);
    this.field = field;
    this.name = 'ValidationError';
  }
}

interface NetworkErrorType {
  type: 'network';
  error: NetworkError;
}

interface ValidationErrorType {
  type: 'validation';
  error: ValidationError;
}

type AppError = NetworkErrorType | ValidationErrorType;

function fetchData(input: string): string {
  if (input.length < 5) {
    throw new ValidationError('Input too short', 'input');
  }
  if (input === 'network') {
    throw new NetworkError('Network connection failed', 503);
  }
  return 'Data fetched successfully!';
}

try {
  const result = fetchData('net');
  console.log(result);
} catch (err) {
  if (err instanceof ValidationError) {
    console.error(`Validation error on field: ${err.field}, message: ${err.message}`);
  } else if (err instanceof NetworkError) {
    console.error(`Network error code: ${err.code}, message: ${err.message}`);
  } else {
    console.error('Unknown error:', err);
  }
}

try {
  const input = 'network';
  if (input.length < 5) {
    throw { type: 'validation', error: new ValidationError('Input too short', 'input') } as AppError;
  }
  if (input === 'network') {
    throw { type: 'network', error: new NetworkError('Network connection failed', 503) } as AppError;
  }
} catch (err) {
  const appError = err as AppError;
  switch (appError.type) {
    case 'validation':
      console.error(`Validation error: ${appError.error.message} on field ${appError.error.field}`);
      break;
    case 'network':
      console.error(`Network error code ${appError.error.code}: ${appError.error.message}`);
      break;
  }
}

